def main(argv: list[str] | None = None) -> None:
    args = build_parser().parse_args(argv)

    text = sys.stdin.read() if args.text == "-" else args.text

    stages = [TokenizerStage()]
    if args.upper:
        stages.append(UpperTransform())
    if args.lower:
        stages.append(LowerTransform())
    if args.reverse:
        stages.append(ReverseTransform())
    stages.append(FORMATTERS[args.format]())

    pipe = Pipeline(stages)
    print(pipe.run(text))

def run(self, text: str) -> str:
    from .tokenizer import TokenizerStage
    from .formatter import PlainFormatter

    tokens = TokenizerStage().process([Token(text=text)])
    for stage in self._stages:
        if isinstance(stage, TokenizerStage):
            continue
        tokens = stage.process(tokens)
    formatter = next(
        (s for s in self._stages if hasattr(s, "format")),
        PlainFormatter(),
    )
    return formatter.format(tokens)
